// Parse the analyst's JSON magazine and build the cover-image prompt.
const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;            // Ollama
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text; // Claude
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
if (!data || typeof data !== 'object') {
  data = { title: 'Security Awareness Digest', weekOf: '', intro: 'This edition could not be generated in full; please re-run.', feature: null, threats: [], awareness: [], quals: [], glossary: [] };
}
const date = (($('Aggregate Sources').first() || {}).json || {}).date || new Date().toISOString().slice(0, 10);
const title = data.title || 'Security Awareness Digest';
const coverPrompt = 'Wide cinematic, semi-realistic editorial cover illustration for a premium corporate SECURITY-AWARENESS magazine titled "' + title + '". Bright modern office, diverse professionals, calm and trustworthy mood; soft natural window light; teal and deep-navy colour grade; strong empty space on the left third for a title overlay. No text, no words, no letters, no logos, no watermark, no charts, no screenshots.';
return [{ json: { data: data, title: title, date: date, coverPrompt: coverPrompt } }];

// Generate the magazine cover image via the shared image provider (graceful:
// empty string => the renderer falls back to a branded gradient cover).
const j = $json || {};
let cover = '';
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const wantImages = (($env.LEARNING_HUB_COVER_IMAGE || $env.CYBER_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false');
if (wantImages && key && j.coverPrompt) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1') + '/images/generations',
      headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
      body: { model: ($env.IMAGE_MODEL || 'gpt-image-1'), prompt: j.coverPrompt, size: ($env.IMAGE_SIZE || '1024x1536'), n: 1 },
      json: true, timeout: 180000
    });
    const b64 = resp && resp.data && resp.data[0] && resp.data[0].b64_json;
    if (b64) cover = 'data:image/png;base64,' + b64;
  } catch (e) { cover = ''; }
}
return [{ json: Object.assign({}, j, { cover: cover }) }];

// Render the staff security-awareness magazine as one premium, print-ready A4 HTML
// (cover + editorial + feature + threats + human-firewall tips + skills + glossary).
// Self-contained inline CSS; Gotenberg turns it into the PDF. Returns the parsed
// magazine data alongside the HTML so the course can be grounded in it.
const j = $json || {};
const data = j.data || {};
const date = j.date || new Date().toISOString().slice(0, 10);
const title = j.title || data.title || 'Security Awareness Digest';
const weekOf = data.weekOf || '';
const cover = j.cover || '';
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function paras(s){ return String(s==null?'':s).split(/\n+/).map(function(p){return p.trim();}).filter(Boolean).map(function(p){return '<p>'+esc(p)+'</p>';}).join(''); }
const A = function(x){ return Array.isArray(x)?x:[]; };

const CSS = "@page{size:A4;margin:0} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;color:#11151C;line-height:1.55}"
+".page{width:210mm;min-height:297mm;position:relative;background:#fff;overflow:hidden}"
+".content{padding:22mm 18mm 20mm}"
+".cover{color:#fff;background:#0A1A2F;page-break-after:always;display:flex;flex-direction:column;justify-content:space-between;height:296mm;padding:18mm}"
+".cover .bg{position:absolute;inset:0;background-size:cover;background-position:center;z-index:0}"
+".cover .bg.ph{background:linear-gradient(135deg,#0A1A2F,#0E7C86)}"
+".cover .grad{position:absolute;inset:0;background:linear-gradient(180deg,rgba(8,18,28,.30),rgba(8,18,28,.92));z-index:1}"
+".cover .inner{position:relative;z-index:2}"
+".cover .kicker{letter-spacing:4px;text-transform:uppercase;font-size:12px;font-weight:800;color:#E7C76A}"
+".cover h1{font-size:46px;line-height:1.05;margin:10px 0 8px;font-weight:800}"
+".cover .edition{font-size:14px;color:#cfe0e6;letter-spacing:1px}"
+".cover .dek{margin-top:14px;font-size:15px;color:#e7eef2;max-width:150mm}"
+".cover .brandbar{position:relative;z-index:2;display:flex;align-items:center;justify-content:space-between;font-size:12px;letter-spacing:2px;color:#9fe4d8;text-transform:uppercase;font-weight:700}"
+".sec{margin:0 0 16mm}"
+".sec h2{font-family:Georgia,serif;font-size:24px;color:#0A1A2F;margin:0 0 4px;display:flex;align-items:center;gap:10px}"
+".sec h2:before{content:'';width:22px;height:3px;background:#C9A24B;display:inline-block;border-radius:2px}"
+".sec .lead{color:#5A6472;font-size:13px;margin:0 0 12px}"
+"p{font-size:13.5px;margin:0 0 9px;color:#1d2733}"
+".feature{background:#F4F6F9;border-left:4px solid #0E7C86;border-radius:10px;padding:16px 18px}"
+".feature .hl{font-family:Georgia,serif;font-size:22px;color:#0A1A2F;font-weight:700;margin:0 0 2px}"
+".feature .deck{font-style:italic;color:#5A6472;margin:0 0 10px}"
+".feature ul{margin:8px 0 0;padding-left:18px}.feature li{font-size:13px;margin:4px 0;color:#0A1A2F}"
+".grid{display:grid;grid-template-columns:1fr 1fr;gap:10px}"
+".card{border:1px solid #E2E6EC;border-radius:10px;padding:12px 14px;background:#fff}"
+".card h3{margin:0 0 5px;font-size:14px;color:#0A1A2F}.card p{font-size:12.5px;margin:0;color:#46505c}"
+".tip{display:flex;gap:10px;align-items:flex-start;border:1px solid #E2E6EC;border-left:4px solid #C9A24B;border-radius:10px;padding:10px 12px;background:#fff}"
+".tip .n{flex:0 0 auto;width:22px;height:22px;border-radius:50%;background:#0E7C86;color:#fff;font-size:12px;font-weight:800;display:flex;align-items:center;justify-content:center}"
+".tip h3{margin:0 0 2px;font-size:13.5px;color:#0A1A2F}.tip p{margin:0;font-size:12.5px;color:#46505c}"
+".qual{border:1px solid #E2E6EC;border-radius:10px;padding:11px 14px;margin:0 0 8px}.qual h3{margin:0;font-size:14px;color:#0A1A2F}.qual .prov{font-size:11px;letter-spacing:1px;text-transform:uppercase;color:#0E7C86;font-weight:700;margin:1px 0 5px}.qual p{margin:0;font-size:12.5px;color:#46505c}"
+".gloss{display:grid;grid-template-columns:1fr 1fr;gap:8px 18px}.gloss .g b{color:#0A1A2F}.gloss .g{font-size:12.5px;color:#46505c;border-bottom:1px solid #eef1f5;padding:5px 0}"
+".foot{position:absolute;left:18mm;right:18mm;bottom:10mm;border-top:1px solid #E2E6EC;padding-top:5px;display:flex;justify-content:space-between;color:#9aa6b2;font-size:10px}";

// ---- cover ----
let html = '<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>';
html += '<section class="page cover">'
 + (cover ? ('<div class="bg" style="background-image:url('+cover+')"></div>') : '<div class="bg ph"></div>')
 + '<div class="grad"></div>'
 + '<div class="brandbar"><span>Security Awareness</span><span>Learning Hub</span></div>'
 + '<div class="inner"><div class="kicker">Staff Awareness Magazine</div>'
 + '<h1>'+esc(title)+'</h1>'
 + '<div class="edition">'+esc(weekOf||date)+'</div>'
 + (data.intro?('<div class="dek">'+esc(data.intro)+'</div>'):'')
 + '</div></section>';

// ---- content ----
html += '<section class="page"><div class="content">';
if (data.intro) html += '<div class="sec"><h2>Editor’s Welcome</h2>'+paras(data.intro)+'</div>';
const f = data.feature;
if (f && (f.headline || f.body)) {
  html += '<div class="sec"><h2>Feature</h2><div class="feature">'
    + (f.headline?('<div class="hl">'+esc(f.headline)+'</div>'):'')
    + (f.deck?('<div class="deck">'+esc(f.deck)+'</div>'):'')
    + paras(f.body||'')
    + (A(f.takeaways).length?('<ul>'+A(f.takeaways).map(function(t){return '<li>'+esc(t)+'</li>';}).join('')+'</ul>'):'')
    + '</div></div>';
}
const threats = A(data.threats);
if (threats.length) {
  html += '<div class="sec"><h2>Emerging Threats</h2><p class="lead">What’s circulating and what it means for you.</p><div class="grid">'
    + threats.map(function(t){return '<div class="card"><h3>'+esc(t.headline||'')+'</h3><p>'+esc(t.summary||'')+'</p></div>';}).join('')
    + '</div></div>';
}
const aw = A(data.awareness);
if (aw.length) {
  html += '<div class="sec"><h2>The Human Firewall</h2><p class="lead">Practical habits that keep us all safer.</p><div class="grid">'
    + aw.map(function(a,i){return '<div class="tip"><div class="n">'+(i+1)+'</div><div><h3>'+esc(a.tip||'')+'</h3><p>'+esc(a.detail||'')+'</p></div></div>';}).join('')
    + '</div></div>';
}
const quals = A(data.quals);
if (quals.length) {
  html += '<div class="sec"><h2>Skills &amp; Qualifications</h2><p class="lead">Ways to grow your security know-how.</p>'
    + quals.map(function(q){return '<div class="qual"><h3>'+esc(q.name||'')+'</h3><div class="prov">'+esc(q.provider||'')+'</div><p>'+esc(q.summary||'')+'</p></div>';}).join('')
    + '</div>';
}
const gl = A(data.glossary);
if (gl.length) {
  html += '<div class="sec"><h2>Jargon Buster</h2><div class="gloss">'
    + gl.map(function(g){return '<div class="g"><b>'+esc(g.term||'')+'</b> — '+esc(g.definition||'')+'</div>';}).join('')
    + '</div></div>';
}
html += '</div><div class="foot"><span>Security Awareness · Learning Hub</span><span>'+esc(weekOf||date)+'</span></div></section>';
html += '</body></html>';

const fileSafe = (title.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)) || 'edition';
return [{ json: { data: data, html: html, date: date, title: title, weekOf: weekOf, fileSafe: 'learning-hub-'+date } }];

// Wrap the rendered magazine HTML as an index.html binary for Gotenberg.
const meta = $('Render Magazine').first().json;
const buf = Buffer.from(meta.html || '<html></html>', 'utf8');
const bin = await this.helpers.prepareBinaryData(buf, 'index.html', 'text/html');
return [{ json: { date: meta.date, fileSafe: meta.fileSafe }, binary: { data: bin } }];

// Persist the magazine: PDF (from Gotenberg) + HTML + structured JSON archive.
// Carries the parsed magazine data forward so the course can be grounded in it.
const fs = require('fs');
const meta = $('Render Magazine').first().json;
const dir = '/reports/learning-hub';
const archive = '/reports/archive/learning-hub';
const base = meta.fileSafe; // learning-hub-<date>
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
try { fs.mkdirSync(archive, { recursive: true }); } catch (e) {}
let pdfPath = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) { fs.writeFileSync(dir + '/' + base + '.pdf', buf); fs.writeFileSync(archive + '/' + base + '.pdf', buf); pdfPath = dir + '/' + base + '.pdf'; }
} catch (e) { pdfPath = ''; }
try { fs.writeFileSync(dir + '/' + base + '.html', meta.html); } catch (e) {}
try { fs.writeFileSync(archive + '/' + base + '.json', JSON.stringify({ title: meta.title, weekOf: meta.weekOf, date: meta.date, data: meta.data }, null, 2)); } catch (e) {}
return [{ json: {
  ok: true,
  date: meta.date,
  title: meta.title,
  weekOf: meta.weekOf,
  data: meta.data,
  magazinePdf: pdfPath || (dir + '/' + base + '.pdf'),
  magazineHtml: dir + '/' + base + '.html',
  fileSafe: base
} }];

// Build the e-learning "source" grounding text + course metadata from the magazine.
// Output is fed to the module's e-learning workflow (Execute Workflow) and reused
// by Register Publication. Keeps the course strictly about this edition's content.
const m = $json || {};
const data = m.data || {};
const date = m.date || new Date().toISOString().slice(0, 10);
const A = function (x) { return Array.isArray(x) ? x : []; };
function line(s) { return String(s == null ? '' : s).replace(/\s+/g, ' ').trim(); }
const parts = [];
parts.push('MAGAZINE TITLE: ' + (m.title || data.title || 'Security Awareness Digest'));
if (data.intro) parts.push('EDITORIAL: ' + line(data.intro));
const f = data.feature;
if (f && (f.headline || f.body)) {
  parts.push('FEATURE: ' + line(f.headline || '') + (f.deck ? (' — ' + line(f.deck)) : ''));
  if (f.body) parts.push(line(f.body));
  if (A(f.takeaways).length) parts.push('Key takeaways: ' + A(f.takeaways).map(line).join('; '));
}
if (A(data.threats).length) parts.push('EMERGING THREATS: ' + A(data.threats).map(function (t) { return line(t.headline) + ' — ' + line(t.summary); }).join(' | '));
if (A(data.awareness).length) parts.push('AWARENESS TIPS: ' + A(data.awareness).map(function (a) { return line(a.tip) + ': ' + line(a.detail); }).join(' | '));
if (A(data.quals).length) parts.push('SKILLS & QUALIFICATIONS: ' + A(data.quals).map(function (q) { return line(q.name) + ' (' + line(q.provider) + '): ' + line(q.summary); }).join(' | '));
if (A(data.glossary).length) parts.push('GLOSSARY: ' + A(data.glossary).map(function (g) { return line(g.term) + ' = ' + line(g.definition); }).join(' | '));
const source = parts.join('\n');
const title = (m.title || data.title || 'Security Awareness Digest') + ' — Awareness Course';
const pm = parseInt(($env.LEARNING_HUB_PASS_MARK || '80'), 10);
return [{ json: {
  source: source,
  title: title,
  passMark: isNaN(pm) ? 80 : pm,
  format: 'HTML',
  illustrate: (($env.ELEARNING_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false'),
  publicationId: 'learning-hub-' + date,
  courseId: 'course-learning-hub-' + date,
  releaseDate: date
} }];

// Upsert the publication record the dashboard reads. Links the magazine + the
// derived course, with the release date and 30-day completion window.
const fs = require('fs');
const dir = '/reports/learning-hub';
const file = dir + '/publications.json';
const src = ($('Build Course Source').first() || {}).json || {};
const mag = ($('Write Magazine').first() || {}).json || {};
const course = $json || {};
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
let store = { updated: '', publications: [] };
try { const cur = JSON.parse(fs.readFileSync(file, 'utf8')); if (cur && Array.isArray(cur.publications)) store = cur; } catch (e) {}
const entry = {
  id: src.publicationId || ('learning-hub-' + (src.releaseDate || '')),
  title: mag.title || src.title || 'Security Awareness Digest',
  kind: 'magazine',
  releaseDate: src.releaseDate || mag.date || new Date().toISOString().slice(0, 10),
  deadlineDays: 30,
  magazine: { pdf: mag.magazinePdf || '', html: mag.magazineHtml || '' },
  course: { id: src.courseId || '', html: course.html || course.file || '', title: src.title || '', passMark: src.passMark || 80 }
};
store.publications = store.publications.filter(function (p) { return p && p.id !== entry.id; });
store.publications.unshift(entry);
store.publications.sort(function (a, b) { return String(b.releaseDate).localeCompare(String(a.releaseDate)); });
store.updated = new Date().toISOString();
try { fs.writeFileSync(file, JSON.stringify(store, null, 2)); } catch (e) {}
return [{ json: { ok: true, publication: entry, total: store.publications.length, file: file } }];
